using Payments;

namespace Payments.Tests;

[TestClass]
public sealed class PaymentGatewayTests
{
    private readonly PaymentGateway _gateway;

    public PaymentGatewayTests()
    {
        _gateway = new PaymentGateway();
    }

    // --- ChargeAsync Tests ---

    [TestMethod]
    public async Task ChargeAsync_ValidTokenAndAmount_ReturnsSuccess()
    {
        var result = await _gateway.ChargeAsync("tok_valid_visa", 50.00m);

        Assert.IsNotNull(result);
        Assert.IsTrue(result.Success);
        Assert.IsNotNull(result.ChargeId);
    }

    [TestMethod]
    public async Task ChargeAsync_ValidToken_ReturnsNonEmptyChargeId()
    {
        var result = await _gateway.ChargeAsync("tok_valid_visa", 25.00m);

        Assert.IsNotNull(result.ChargeId);
        Assert.AreNotEqual(string.Empty, result.ChargeId);
    }

    [TestMethod]
    [DataRow(0.01)]
    [DataRow(1.00)]
    [DataRow(9999.99)]
    public async Task ChargeAsync_VariousValidAmounts_ReturnsSuccess(double amount)
    {
        var result = await _gateway.ChargeAsync("tok_valid", (decimal)amount);

        Assert.IsTrue(result.Success);
    }

    [TestMethod]
    public async Task ChargeAsync_NullCardToken_ThrowsArgumentNullException()
    {
        await Assert.ThrowsExactlyAsync<ArgumentNullException>(
            async () => await _gateway.ChargeAsync(null!, 10.00m));
    }

    [TestMethod]
    public async Task ChargeAsync_EmptyCardToken_ThrowsArgumentException()
    {
        await Assert.ThrowsExactlyAsync<ArgumentException>(
            async () => await _gateway.ChargeAsync(string.Empty, 10.00m));
    }

    [TestMethod]
    [DataRow(0)]
    [DataRow(-1)]
    [DataRow(-100.50)]
    public async Task ChargeAsync_ZeroOrNegativeAmount_ThrowsArgumentOutOfRangeException(double amount)
    {
        await Assert.ThrowsExactlyAsync<ArgumentOutOfRangeException>(
            async () => await _gateway.ChargeAsync("tok_valid", (decimal)amount));
    }

    [TestMethod]
    public async Task ChargeAsync_DeclinedCard_ReturnsFailure()
    {
        var result = await _gateway.ChargeAsync("tok_declined", 50.00m);

        Assert.IsFalse(result.Success);
    }

    [TestMethod]
    public async Task ChargeAsync_TwoCharges_ReturnDifferentChargeIds()
    {
        var result1 = await _gateway.ChargeAsync("tok_valid", 10.00m);
        var result2 = await _gateway.ChargeAsync("tok_valid", 20.00m);

        Assert.AreNotEqual(result1.ChargeId, result2.ChargeId);
    }

    // --- RefundAsync Tests ---

    [TestMethod]
    public async Task RefundAsync_ValidChargeId_ReturnsSuccess()
    {
        var charge = await _gateway.ChargeAsync("tok_valid", 75.00m);

        var refund = await _gateway.RefundAsync(charge.ChargeId);

        Assert.IsNotNull(refund);
        Assert.IsTrue(refund.Success);
        Assert.IsNotNull(refund.RefundId);
    }

    [TestMethod]
    public async Task RefundAsync_ValidChargeId_ReturnsNonEmptyRefundId()
    {
        var charge = await _gateway.ChargeAsync("tok_valid", 30.00m);

        var refund = await _gateway.RefundAsync(charge.ChargeId);

        Assert.AreNotEqual(string.Empty, refund.RefundId);
    }

    [TestMethod]
    public async Task RefundAsync_NullChargeId_ThrowsArgumentNullException()
    {
        await Assert.ThrowsExactlyAsync<ArgumentNullException>(
            async () => await _gateway.RefundAsync(null!));
    }

    [TestMethod]
    public async Task RefundAsync_EmptyChargeId_ThrowsArgumentException()
    {
        await Assert.ThrowsExactlyAsync<ArgumentException>(
            async () => await _gateway.RefundAsync(string.Empty));
    }

    [TestMethod]
    public async Task RefundAsync_NonExistentChargeId_ReturnsFailure()
    {
        var refund = await _gateway.RefundAsync("ch_nonexistent");

        Assert.IsFalse(refund.Success);
    }

    [TestMethod]
    public async Task RefundAsync_AlreadyRefundedCharge_ReturnsFailure()
    {
        var charge = await _gateway.ChargeAsync("tok_valid", 50.00m);
        await _gateway.RefundAsync(charge.ChargeId);

        var secondRefund = await _gateway.RefundAsync(charge.ChargeId);

        Assert.IsFalse(secondRefund.Success);
    }
}

